"use client";

import { useState, useEffect, useCallback } from "react";

type Tab = { user_id: number; name: string; flat_no: string; phone: string; total_tab: number; total_paid: number; balance: number };

export default function AdminTabsPage() {
  const [tabs, setTabs] = useState<Tab[]>([]);
  const [payingUser, setPayingUser] = useState<number | null>(null);
  const [payAmount, setPayAmount] = useState("");

  const fetchTabs = useCallback(() => { fetch("/api/tabs").then(r => r.json()).then(setTabs); }, []);
  useEffect(() => { fetchTabs(); }, [fetchTabs]);

  async function recordPayment(userId: number) {
    const amount = parseFloat(payAmount);
    if (!amount || amount <= 0) { alert("Enter a valid amount"); return; }
    await fetch("/api/tabs", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ user_id: userId, amount }) });
    setPayingUser(null); setPayAmount(""); fetchTabs();
  }

  const totalOwed = tabs.reduce((s, t) => s + Math.max(0, t.balance), 0);

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-bold text-gray-800">Monthly Tabs</h2>
        <div className="text-right">
          <div className="text-sm text-gray-400">Total Outstanding</div>
          <div className="text-2xl font-bold text-red-600">&#8377;{totalOwed}</div>
        </div>
      </div>

      {tabs.length === 0 && <div className="text-center text-gray-400 py-12">No tabs yet. Tabs appear when users choose &quot;Add to Monthly Tab&quot; payment.</div>}

      <div className="space-y-3">
        {tabs.map(tab => (
          <div key={tab.user_id} className="card p-4">
            <div className="flex items-start justify-between">
              <div>
                <div className="font-bold text-gray-800">{tab.name}</div>
                <div className="text-sm text-gray-500">{tab.flat_no} &middot; {tab.phone}</div>
              </div>
              <div className="text-right">
                <div className={`text-xl font-bold ${tab.balance > 0 ? "text-red-600" : "text-paid"}`}>&#8377;{tab.balance}</div>
                <div className="text-xs text-gray-400">Total: &#8377;{tab.total_tab} | Paid: &#8377;{tab.total_paid}</div>
              </div>
            </div>
            {tab.balance > 0 && (
              <div className="mt-3">
                {payingUser === tab.user_id ? (
                  <div className="flex gap-2">
                    <input type="number" placeholder="Amount" value={payAmount} onChange={e => setPayAmount(e.target.value)} className="input flex-1 !py-2" autoFocus />
                    <button onClick={() => recordPayment(tab.user_id)} className="btn btn-primary px-4 py-2">Record</button>
                    <button onClick={() => { setPayingUser(null); setPayAmount(""); }} className="btn btn-muted px-4 py-2">Cancel</button>
                  </div>
                ) : (
                  <button onClick={() => { setPayingUser(tab.user_id); setPayAmount(String(tab.balance)); }} className="btn btn-ghost w-full py-2">Record Payment</button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
